'use strict';

// src/timeRange/index.ts
function timeRange(start, end, unit = 24) {
  const res = [];
  if (start > end) {
    while (start < unit) {
      res.push(start++);
    }
    let s = 0;
    while (s <= end) {
      res.push(s++);
    }
  } else {
    for (let i = start; i <= end; i++)
      res.push(i);
  }
  return res;
}

exports.timeRange = timeRange;
